import { useEffect, useState } from "react";
import { useParams, useNavigate } from "react-router-dom";
import API from "../services/api";

function PlayerDetails() {
  const { id } = useParams();
  const navigate = useNavigate();
  const [player, setPlayer] = useState(null);
  const [careerStats, setCareerStats] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    const fetchPlayerAndStats = async () => {
      try {
        setLoading(true);
        const playerRes = await API.get(`/players/${id}`);
        setPlayer(playerRes.data);

        try {
          const statsRes = await API.get(`/players/${id}/stats`);
          setCareerStats(statsRes.data);
        } catch (statsErr) {
          console.error("Error fetching career stats:", statsErr);
        }
      } catch (err) {
        setError("Player not found or error fetching details.");
        console.error(err);
      } finally {
        setLoading(false);
      }
    };
    fetchPlayerAndStats();
  }, [id]);

  if (loading) return <div className="page"><p>Loading player details...</p></div>;
  if (error) return <div className="page"><p style={{ color: 'red' }}>{error}</p></div>;
  if (!player) return <div className="page"><p>Player not found.</p></div>;

  return (
    <div className="page">
      <button onClick={() => navigate(-1)} className="login-btn" style={{ width: 'auto', marginBottom: '20px', padding: '8px 16px' }}>
        ← Back to Players
      </button>

      <div className="player-profile-card" style={{ maxWidth: '900px', margin: '0 auto' }}>
        <div className="profile-header">
          <div style={{ display: 'flex', gap: '10px', alignItems: 'center', marginBottom: '10px' }}>
             <span style={{ fontSize: '1.5rem' }}>🇮🇳</span>
             <span style={{ fontSize: '1rem', fontWeight: 'bold', textTransform: 'uppercase', color: 'var(--cyan)' }}>{player.team}</span>
          </div>
          <div className="profile-name" style={{ fontSize: '2.5rem' }}>{player.name}</div>
          <div className="profile-role" style={{ fontSize: '1.2rem' }}>
            <span style={{ color: 'var(--cyan)' }}>≫</span> {player.role}
          </div>
        </div>

        <h3 style={{ padding: '20px 20px 0', margin: 0, color: 'var(--cyan)' }}>Aggregated Match Stats</h3>
        <div className="stats-container" style={{ gridTemplateColumns: 'repeat(auto-fit, minmax(140px, 1fr))', gap: '15px', padding: '20px' }}>
          <div className="stat-item">
            <div className="stat-label">MATCHES</div>
            <div className="stat-value">{careerStats?.matchesPlayed || 0}</div>
          </div>
          <div className="stat-item">
            <div className="stat-label">TOTAL RUNS</div>
            <div className="stat-value">{careerStats?.totalRuns || 0}</div>
          </div>
          <div className="stat-item">
            <div className="stat-label">BATTING AVG</div>
            <div className="stat-value">{careerStats?.battingAvg?.toFixed(2) || "0.00"}</div>
          </div>
          <div className="stat-item">
            <div className="stat-label">STRIKE RATE</div>
            <div className="stat-value">{careerStats?.strikeRate?.toFixed(2) || "0.00"}</div>
          </div>
          <div className="stat-item">
            <div className="stat-label">HIGHEST SCORE</div>
            <div className="stat-value">{careerStats?.highestScore || 0}</div>
          </div>
          <div className="stat-item">
            <div className="stat-label">50s / 100s</div>
            <div className="stat-value">{careerStats?.fifties || 0} / {careerStats?.centuries || 0}</div>
          </div>
          <div className="stat-item">
            <div className="stat-label">TOTAL WICKETS</div>
            <div className="stat-value">{careerStats?.totalWickets || 0}</div>
          </div>
          <div className="stat-item">
            <div className="stat-label">3w / 5w</div>
            <div className="stat-value">{careerStats?.threeWicketHauls || 0} / {careerStats?.fiveWicketHauls || 0}</div>
          </div>
        </div>

        {careerStats?.matchHistory?.length > 0 && (
          <div style={{ padding: '20px', borderTop: '1px solid rgba(255,255,255,0.1)' }}>
            <h3 style={{ color: 'var(--cyan)', marginBottom: '15px' }}>Match History</h3>
            <div style={{ overflowX: 'auto' }}>
              <table style={{ width: '100%', borderCollapse: 'collapse', color: 'white' }}>
                <thead>
                  <tr style={{ textAlign: 'left', borderBottom: '2px solid var(--dark-gray)' }}>
                    <th style={{ padding: '10px' }}>Opponent</th>
                    <th style={{ padding: '10px' }}>Runs</th>
                    <th style={{ padding: '10px' }}>Wickets</th>
                    <th style={{ padding: '10px' }}>Date</th>
                  </tr>
                </thead>
                <tbody>
                  {careerStats.matchHistory.map((m, i) => (
                    <tr key={i} style={{ borderBottom: '1px solid rgba(255,255,255,0.05)' }}>
                      <td style={{ padding: '10px' }}>{m.opponent}</td>
                      <td style={{ padding: '10px', fontWeight: 'bold' }}>{m.runs}</td>
                      <td style={{ padding: '10px' }}>{m.wickets}</td>
                      <td style={{ padding: '10px', fontSize: '0.85rem', color: '#999' }}>{new Date(m.date).toLocaleDateString()}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          </div>
        )}

        <div style={{ padding: '20px', background: 'rgba(255,255,255,0.05)', borderRadius: '0 0 12px 12px' }}>
            <h3 style={{ color: 'var(--cyan)', marginBottom: '10px' }}>Profile Information</h3>
            <p><strong>Team:</strong> {player.team}</p>
            <p><strong>Role:</strong> {player.role}</p>
            <p><strong>Description:</strong> {player.description || "No description available for this player."}</p>
        </div>
      </div>
    </div>
  );
}

export default PlayerDetails;
